/// Name of a [`Condition`], as a `&'static str`.
///
/// The carry conditions are spelled `hs`/`lo` (the unsigned-comparison aliases),
/// not `cs`/`cc`: these are equivalent ARM UAL synonyms (identical 4-bit
/// encoding) and match the preferred disassembly emitted by the Binary Ninja
/// differential corpus, which uses `hs`/`lo` exclusively.
#[inline]
pub const fn condition_name(c: Condition) -> &'static str {
    match c {
        Condition::Eq => "eq",
        Condition::Ne => "ne",
        Condition::Cs => "hs",
        Condition::Cc => "lo",
        Condition::Mi => "mi",
        Condition::Pl => "pl",
        Condition::Vs => "vs",
        Condition::Vc => "vc",
        Condition::Hi => "hi",
        Condition::Ls => "ls",
        Condition::Ge => "ge",
        Condition::Lt => "lt",
        Condition::Gt => "gt",
        Condition::Le => "le",
        Condition::Al => "al",
        Condition::Nv => "nv",
    }
}

/// System-register name table, sorted by packed key for binary search.
///
/// Each entry is `(packed_key, name)`. The skeleton seeds a couple of common
/// registers; `cargo xtask gen` emits the full sorted set.
static SYSREG_NAMES: &[(u16, &str)] = &[
    // (SystemReg::from_fields(3,3,4,2,0).packed(), "nzcv"), etc.
    // codegen/expand: full sorted (packed, name) table.
];

/// Resolve a packed system-register key to its name via binary search; `None`
/// for unknown keys (the formatter emits the generic `S<...>` syntax).
#[inline]
pub fn sysreg_name(packed: u16) -> Option<&'static str> {
    match SYSREG_NAMES.binary_search_by_key(&packed, |&(k, _)| k) {
        Ok(i) => Some(SYSREG_NAMES[i].1),
        Err(_) => None,
    }
}
